var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"젠장, 또 먹통이야! 이런 고물 무전기 같으니!","JPN":"ちくしょう、また使えなくなったわ！　このポンコツ無線機！","ENG":"Dang it! It's not working again! A piece of junk radio!","TWN":"該死，又故障了！這個老古董！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"자동차 걷어차지 마! 사고 난다고!","JPN":"おいおい、車は蹴るなよ！　事故っちゃうぞ？","ENG":"Stop kicking the car! You'll cause an accident!","TWN":"別踢汽車了！會出事的！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"그보다 답신은? 다른 소대에서 뭐래?","JPN":"返信は？　他の小隊はなんだって？","ENG":"What about the responses? What do the other squads say?","TWN":"得到回覆了嗎？其他小隊說什麼？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"퍽이나 답신이 오겠다. 무전이 제대로 갔는지도 모르는데.","JPN":"返信なんかくるわけないでしょ。無線がちゃんと届いたかもわからないのに。","ENG":"You really think there will be any responses? I'm not even sure if my message got through.","TWN":"現在都不知道無線電有沒有正常發出去，說什麼說啊。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"그럼 큰일난 거 아냐? 점점 따라 잡히고 있다고!","JPN":"それってまずくねえか？　だんだん追いつかれてきてるんだぞ！","ENG":"Then we're screwed, aren't we? That thing is catching up to us real fast!","TWN":"那怎麼辦？我們快被追上了！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"그러니까 처음부터 내 말대로 했어야지, 인간 암컷.","JPN":"だから最初からオルカの言うことを聞けばよかったんだ、のろまなメス。","ENG":"You should have heeded my words, human female.","TWN":"所以剛才就應該聽我說的做了啊，人類女孩。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"지금이라도 늦지 않았어.","JPN":"今からでも遅くない。","ENG":"It's not too late.","TWN":"現在也不晚。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"차를 세워라! 내가 놈을 도륙해 주지!","JPN":"車を止めろ！　オルカが奴をズタズタにしてやる！","ENG":"Stop the car at once! I shall shred them to smithereens!","TWN":"停車！我去解決掉它！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"말했잖아? 네가 전면에 나서면 CRF 소모가 너무 크다고!","JPN":"言ったでしょ？　あんたが本気出すとCRFの消耗が激しすぎるって！","ENG":"Didn't I tell you? If you engage, you'll use up too much CRF!","TWN":"我不是說過了嗎？你如果投入戰鬥CRF消耗太大！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CAR_SKID"},{"id":"L14_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"무슨 상관이지?","JPN":"それがなに？","ENG":"Should I care?","TWN":"跟你有什麼關係？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"이 몸은 이제 내 것이다. 내 마음대로 할 수 있는 거라고!","JPN":"この体はもうオルカのもの。自分の好きなようにできる！","ENG":"This body belongs to me now. I can do with it as I please!","TWN":"這個身體現在是我的。我可以隨意支配！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"젠장, 네가 소모한 CRF를 채워 줄 이터니움은 우리가 벌고 있잖아.","JPN":"だから、あんたが消耗したCRFを満たすエタニウムはこっちが稼いでいるわけよ。","ENG":"We're the ones earning the Eternium to refill the CRF you keep using up, darn it!","TWN":"喂，你消耗完CRF，還不是要靠我們賺永恆之金來填充。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CAR_SKID"},{"id":"L17_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"쓸데없이 낭비를 하면 할수록 간식을 사는 데 쓸 예산도 줄어든다고.","JPN":"無駄に使いまくったらおやつ代の予算が減るんだよ？　いいの？","ENG":"If you waste it willy-nilly, we won't have enough money to buy snacks.","TWN":"別隨便浪費，不然買零食的預算也少了。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"새, 생각해 보니 저런 하찮은 놈을 내가 직접 상대할 필요는 없겠지.","JPN":"よ、よく考えたらあの程度の奴、オルカが直接相手する必要はなさそうだ。","ENG":"C-come to think of it, I suppose there's no need to personally engage such a petty creature.","TWN":"好，好吧，那種傢伙的確不需要我親自出手。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"난 바쁜 일이 있어서 내려가 있겠다.","JPN":"ちょっと急用ができたから下がっておく。","ENG":"I shall retire for now, as I'm rather busy with another matter.","TWN":"我還有事，先下去了。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"내 몸이 다치지 않게 잘 지키도록, 인간!","JPN":"この体が怪我しないようちゃんと守れよ、人間！","ENG":"Take good care of my flesh, human!","TWN":"好好保護這個身體，人類女孩！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"......바쁜 일은 또 뭐야? 머릿속에 비밀 친구들이라도 만들었어?","JPN":"……急用ってなによ？　頭の中で秘密の友達でも作ったの？","ENG":"Busy with what? You got a bunch of imaginary friends coming for a tea party in your head?","TWN":"……你是怎麼了？難道是在自己腦海中交了什麼秘密朋友嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"......제시카.","JPN":"……ジェシカ。","ENG":"...Jessica.","TWN":"……潔西卡。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"교대했구나. 아까 다친 데는 좀 어때?","JPN":"交代したのね。さっきの傷はどう？","ENG":"So you're back. How's your injury coming along?","TWN":"回來了？剛才受的傷怎麼樣了？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"응. 많이 재생됐어. 다시 싸워도 괜찮아.","JPN":"かなり再生できたよ。また戦ってもいい。","ENG":"Good. I've regenerated quite a bit. I'm good to fight again.","TWN":"嗯，已經修復很多了，可以繼續戰鬥。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"그런데 교대하면서 오르카가 힘 낭비하지 말고 효율적으로 싸우래.","JPN":"でも、交代する時オルカに無駄に力使うのはやめて、効率的に戦えって言われた。","ENG":"But Orca told me that I should use my energy sparingly when we switched.","TWN":"不過剛才替換的時候奧爾卡說別浪費力量，要注重效率。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"둘이 무슨 얘기를 했던 거야?","JPN":"2人で何の話をしたの？","ENG":"What were you guys talking about?","TWN":"你們聊了什麼？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"음...... 합리적인 소비의 중요성이랄까?","JPN":"えーと……合理的な消費の重要性かな？","ENG":"Um... The importance of sensible frugality, I guess?","TWN":"嗯……可以說是提醒我適當消費的重要性？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"......?","JPN":"……？","ENG":"......?","TWN":"……？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"이런, 앞에도 한 마리 더 숨어 있었어!!","JPN":"しまった、前の方に1匹隠れやがってた！！","ENG":"Dang it! There's another one hiding in front!","TWN":"天啊，前面還藏著一隻！！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"부딪친다, 다들 꽉 잡아!!","JPN":"ぶつかるぞ！　つかまれ！","ENG":"We're going to crash! Hang tight!","TWN":"要撞上了，都抓緊了！！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"뭐, 뭐야? 3종 침식체가 튕겨 나갔잖아? 데굴데굴 굴러가는데?","JPN":"な、なに？　第3種侵食体が弾き飛ばされたの？　めっちゃ遠くまで転がっていっちゃったわ。","ENG":"H-huh? The Category 3 just got bounced off? It's rolling over?","TWN":"怎麼回事？3類侵蝕體被撞飛了！怎麼一直在滾？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"이 장갑차, 그렇게 단단했었나?","JPN":"この装甲車ってそんなに頑丈だったっけ……","ENG":"Since when was this armored vehicle so sturdy?","TWN":"這輛裝甲車這麼堅固嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"......그게 아니야.","JPN":"……違う。","ENG":"That's not it.","TWN":"……不對。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"동료들이 왔어.","JPN":"仲間が来た。","ENG":"Our backup has arrived.","TWN":"是同伴們來了。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......방금 주먹으로 3종 침식체를 후려친 거야?","JPN":"今……素手で第3種侵食体を吹き飛ばしたの？","ENG":"Did she just knock down a Category 3 with her bare fist?","TWN":"……剛才是用拳頭打飛了3類侵蝕體？"},"stage":{"bg":"MAINSTREAM_6100018","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 제 스승님이지만 정말 야만스럽다니까요.","JPN":"ハハハ、僕の師匠とはいえ本当に野蛮ですね。","ENG":"Hah hah, I must admit the Master can be rather barbaric at times.","TWN":"哈哈，雖然是我的師父，但真是野蠻呢。"},"stage":{"bg":"MAINSTREAM_6100018","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"저럴 거면 칼은 왜 들고 다니시는 걸까요.","JPN":"あんなことするなら、剣を携帯する必要ないのに。","ENG":"I don't get why she bothers carrying those swords around.","TWN":"不過那刀難道是裝飾嗎，幹嘛用拳頭呢。"},"stage":{"bg":"MAINSTREAM_6100018","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"여기는 펜릴 소대장, 힐데.","JPN":"こちらフェンリル小隊長、ヒルデ。","ENG":"This is Hilde, Commander of Fenrir Squad.","TWN":"我是芬里爾小隊，希爾德。"},"stage":{"bg":"MAINSTREAM_6100018","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"제 3소대가 유인해 온 3종 침식체와 조우했다.","JPN":"第3小隊がおびき寄せた第3種侵食体と遭遇した。","ENG":"We've made contact with the Category 3 lured here by Squad 3.","TWN":"已碰到第3小隊引誘來的3類侵蝕體。"},"stage":{"bg":"MAINSTREAM_6100018","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"제 2소대는......","JPN":"第2小隊は……","ENG":"As for Squad 2...","TWN":"第2小隊呢……"},"stage":{"bg":"MAINSTREAM_6100018","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"여기 있어요, 힐데 소대장님!","JPN":"こちらです、ヒルデ小隊長！","ENG":"We're here, Commander Hilde!","TWN":"在這裡呢，希爾德小隊長！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"알트 소대, 유인 작전을 마치고 본대 합류를 보고합니다!","JPN":"アルト小隊、誘引作戦を終えて本隊との合流を報告します！","ENG":"ALT Squad has completed its mission and linked up with the main effort!","TWN":"報告！阿爾特小隊已完成引誘作戰，成功與大隊匯合！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"좋아, 계획했던 합류시점보다 조금 이르지만 뭐 상관없겠지.","JPN":"よし、計画していた合流タイミングより少し早いが、まあいいだろう。","ENG":"Good. We're slightly ahead of schedule, but I suppose it doesn't matter.","TWN":"很好，比預定時間點早一些，但沒關係。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"제 2, 제 3 소대는 빠져나가는 놈이 없도록 포위망을 만들도록!","JPN":"第2、第3小隊は逃げだす者がいないように包囲網を張れ！","ENG":"Squads 2 and 3, surround the C.O.s and keep them pinned down!","TWN":"第2、第3小隊要確保沒有漏網之魚，完成包圍圈！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"여기서 놈들을 격멸한다!","JPN":"ここで奴らを撃滅する！","ENG":"We'll exterminate them all right here!","TWN":"把敵人殲滅！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};